import importlib.metadata
import re

# Parse requirements.txt for comparison
with open('/Users/[REDACTED]/hc-grc/requirements.txt') as f:
    reqs = [line.strip() for line in f if line.strip() and not line.startswith('#')]

packages_to_check = [
    'numpy', 'pandas', 'langgraph', 'langchain-core', 'pydantic', 'PyYAML',
    'pytest', 'pytest-cov', 'psycopg', 'langgraph-checkpoint',
    'langgraph-checkpoint-postgres', 'mlflow', 'scipy'
]

print("Checking installed vs declared versions:")
print("=" * 80)

installed = {}
for pkg in packages_to_check:
    try:
        # Try both underscore and dash versions
        try:
            dist = importlib.metadata.distribution(pkg)
        except:
            dist = importlib.metadata.distribution(pkg.replace('-', '_'))
        installed[pkg] = dist.version
    except:
        installed[pkg] = "NOT INSTALLED"

for req_line in reqs:
    match = re.match(r'([a-zA-Z0-9_\-]+)', req_line)
    if match:
        pkg = match.group(1)
        if pkg in installed:
            status = "OK" if installed[pkg] != "NOT INSTALLED" else "MISSING"
            print(f"{pkg:40} {req_line:40} -> {installed[pkg]:20} [{status}]")
EOF

